from typing import Protocol

class Logger(Protocol):
    def log(self, msg: str) -> None:
        ...

class ConsoleLogger:
    def log(self, msg: str) -> None:
        print(f'CONSOLE: {msg}')

def process_data(logger: Logger):
    logger.log('Data processed')

logger = ConsoleLogger()
process_data(logger)

